import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

public class SecureXSSExample {

    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Properly escaping user input before outputting it to the HTML page
        String escapedUserInput = "";
        try {
            escapedUserInput = ESAPI.encoder().encodeForHTML(userInput);
        } catch (EncodingException e) {
            System.err.println("Error while encoding user input: " + e.getMessage());
        }

        System.out.println("<div>" + escapedUserInput + "</div>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
